    # Functions
    ("Comp Sci", "Functions", "What is the difference between actual parameters and formal parameters?", "Actual parameters are the values passed during a function call, whereas formal parameters are the variables defined in the function header.", "EASY"),
    ("Comp Sci", "Functions", "Explain the LEGB rule for variable scope in Python.", "LEGB stands for Local, Enclosing, Global, and Built-in scopes, which is the order Python searches for a variable name.", "MODERATE"),
    ("Comp Sci", "Functions", "What is the rule for using default arguments in a Python function?", "Non-default arguments cannot follow default arguments in a function definition.", "MODERATE"),
    ("Comp Sci", "Functions", "How can a function return multiple values in Python?", "By packing them into a tuple separated by commas (e.g., return a, b, c).", "EASY"),
    ("Comp Sci", "Functions", "What is the purpose of the 'global' keyword in Python?", "It allows a user to modify a global variable inside a local scope (like a function).", "HARD"),
    ("Comp Sci", "Functions", "What are keyword arguments in Python?", "Arguments passed to a function by explicitly specifying the parameter name, allowing them to be passed in any order.", "EASY"),
    ("Comp Sci", "Functions", "What will happen if you pass a mutable object (like a list) to a function and modify it inside?", "The changes will be reflected in the original object outside the function because lists are passed by reference.", "HARD"),
    ("Comp Sci", "Functions", "Define a void function.", "A function that does not return any value (implicitly returns None).", "EASY"),
    ("Comp Sci", "Functions", "What is the difference between a built-in function and a user-defined function?", "Built-in functions are pre-defined in Python (like len(), print()), while user-defined functions are created by the programmer using the 'def' keyword.", "EASY"),
    ("Comp Sci", "Functions", "Explain the concept of variable shadowing in Python functions.", "It occurs when a local variable inside a function has the same name as a global variable, causing the local variable to 'hide' the global one within the function's scope.", "MODERATE"),
    ("Comp Sci", "Functions", "Can a Python function return another function? What is this called?", "Yes, it can. This concept is closely related to closures and higher-order functions.", "HARD"),
    ("Comp Sci", "Functions", "What happens if you pass a mutable list to a function and reassign the entire list variable to a new list inside the function?", "The original list outside the function remains unchanged, as the local variable now points to a completely new object in memory.", "HARD"),
    ("Comp Sci", "Functions", "What are positional arguments?", "Arguments passed to a function in the exact order in which the parameters were defined in the function header.", "EASY"),
    ("Comp Sci", "Functions", "Identify the error: def calc(a=10, b): return a+b", "SyntaxError: non-default argument follows default argument.", "MODERATE"),
    ("Comp Sci", "Functions", "How can you access a global variable inside a function without modifying it?", "You can simply use the variable's name; Python will automatically search the global scope if it is not found locally.", "EASY"),
    ("Comp Sci", "Functions", "What is the data type of the result when a function returns multiple values separated by commas?", "A tuple.", "MODERATE"),
    ("Comp Sci", "Functions", "What is an anonymous function in Python?", "A function defined without a name, typically created using the 'lambda' keyword.", "MODERATE"),
    ("Comp Sci", "Functions", "Is it mandatory to have a return statement in a Python function?", "No, if omitted, the function automatically returns None.", "EASY"),
    ("Comp Sci", "Functions", "What is the scope of a variable defined inside an if-block within a function?", "It has local scope for the entire function, not just the if-block (Python does not have block-level scope, only function-level).", "HARD"),
    ("Comp Sci", "Functions", "How are *args and **kwargs used in function definitions?", "*args allows passing a variable number of positional arguments (as a tuple), and **kwargs allows passing a variable number of keyword arguments (as a dictionary).", "HARD"),
    ("Comp Sci", "Functions", "What is a docstring in a Python function?", "A string literal occurring as the first statement in a function, used for documenting its purpose and usage.", "EASY"),
    ("Comp Sci", "Functions", "What will id(x) return inside a function if x is passed by object reference?", "It returns the memory address of the object, which will be identical to the id of the original object passed during the call.", "MODERATE"),
    ("Comp Sci", "Functions", "Why is it dangerous to use a mutable object (like an empty list) as a default argument?", "Because the default object is created only once when the function is defined, meaning subsequent calls will share and modify the exact same list.", "HARD"),

    # Recursion
    ("Comp Sci", "Recursion", "What are the two essential components of a recursive function?", "A base case (to terminate recursion) and a recursive step (calling itself).", "EASY"),
    ("Comp Sci", "Recursion", "What happens if a recursive function does not have a base case?", "It leads to infinite recursion and eventually raises a RecursionError when the maximum recursion depth is exceeded.", "MODERATE"),
    ("Comp Sci", "Recursion", "Why is the iterative approach sometimes preferred over recursion?", "Because recursion uses more memory (call stack for each function call) and can be slower due to function call overhead.", "HARD"),
    ("Comp Sci", "Recursion", "What is Tail Recursion?", "A recursive function where the recursive call is the very last operation performed in the function.", "HARD"),
    ("Comp Sci", "Recursion", "Name the data structure used internally by Python to manage recursive function calls.", "Stack (Call Stack).", "MODERATE"),
    ("Comp Sci", "Recursion", "Identify the base case in a recursive factorial function.", "if n == 0 or n == 1: return 1", "EASY"),
    ("Comp Sci", "Recursion", "What is the default maximum recursion depth in Python?", "Usually 1000 (can be checked/changed using the sys module).", "MODERATE"),
    ("Comp Sci", "Recursion", "What is the primary difference between recursion and iteration?", "Recursion involves a function calling itself, utilizing the call stack, while iteration uses looping constructs like 'for' or 'while'.", "MODERATE"),
    ("Comp Sci", "Recursion", "Why does a recursive function consume more memory than an iterative one?", "Because each recursive call adds a new frame to the call stack, storing local variables and return addresses.", "HARD"),
    ("Comp Sci", "Recursion", "Write the recursive step for finding the sum of the first N natural numbers.", "return N + sum_natural(N - 1)", "MODERATE"),
    ("Comp Sci", "Recursion", "Write the base case for finding the nth term of the Fibonacci series.", "if n <= 1: return n (or if n == 0: return 0; elif n == 1: return 1)", "EASY"),
    ("Comp Sci", "Recursion", "What exception is raised when you forget to include a base case in a recursive function?", "RecursionError: maximum recursion depth exceeded.", "EASY"),
    ("Comp Sci", "Recursion", "How can you change the default recursion limit in Python?", "By importing the sys module and using sys.setrecursionlimit(limit).", "MODERATE"),
    ("Comp Sci", "Recursion", "Is binary search typically implemented iteratively or recursively?", "It can be implemented both ways, but recursion provides a very clean, intuitive divide-and-conquer implementation.", "MODERATE"),
    ("Comp Sci", "Recursion", "In a recursive binary search, what is the base case for an unsuccessful search?", "When the start index becomes greater than the end index (low > high).", "HARD"),
    ("Comp Sci", "Recursion", "What is direct recursion?", "When a function explicitly calls itself within its own body.", "EASY"),
    ("Comp Sci", "Recursion", "What is indirect recursion?", "When function A calls function B, and function B in turn calls function A.", "HARD"),
    ("Comp Sci", "Recursion", "Why is finding the Fibonacci sequence using simple recursion highly inefficient?", "Because it recalculates the same subproblems multiple times, leading to an exponential time complexity (O(2^n)).", "HARD"),
    ("Comp Sci", "Recursion", "Write the recursive step to reverse a string 's'.", "return s[-1] + reverse(s[:-1])", "HARD"),
    ("Comp Sci", "Recursion", "What is the 'call stack'?", "A stack data structure that stores information about the active subroutines (function calls) of a comp program.", "MODERATE"),
    ("Comp Sci", "Recursion", "What happens to local variables when a recursive function hits its base case?", "The function begins to return, and the local variables of each stacked frame are evaluated as the stack unwinds.", "HARD"),
    ("Comp Sci", "Recursion", "State one major advantage of using recursion.", "It makes the code shorter, cleaner, and easier to understand for problems that have a natural recursive structure (like trees or graphs).", "MODERATE"),

    # File Handling
    ("Comp Sci", "File Handling", "Differentiate between the 'w' and 'a' file opening modes.", "'w' opens a file for writing and truncates (overwrites) it if it exists, while 'a' opens for appending data at the end.", "EASY"),
    ("Comp Sci", "File Handling", "What is the difference between read() and readlines() methods?", "read() reads the entire file as a single string, whereas readlines() reads all lines and returns them as a list of strings.", "MODERATE"),
    ("Comp Sci", "File Handling", "What is the purpose of the tell() method in file handling?", "It returns the current position (byte offset) of the file pointer within the file.", "MODERATE"),
    ("Comp Sci", "File Handling", "How does the seek() method work?", "It changes the current file position to a specified byte offset (e.g., file_object.seek(offset, whence)).", "HARD"),
    ("Comp Sci", "File Handling", "What does the 'r+' mode do?", "It opens a file for both reading and writing; the file pointer is placed at the beginning of the file.", "MODERATE"),
    ("Comp Sci", "File Handling", "Why is it recommended to open files using the 'with' statement?", "Because it automatically closes the file after the nested block of code executes, even if exceptions occur.", "EASY"),
    ("Comp Sci", "File Handling", "What is the absolute path of a file?", "The complete path starting from the root directory to the specific file.", "EASY"),
    ("Comp Sci", "File Handling", "What does the readline() method return if the end of the file is reached?", "An empty string ('').", "MODERATE"),
    ("Comp Sci", "File Handling", "What is the difference between a text file and a binary file?", "Text files store data as human-readable characters using encodings like ASCII/UTF-8, whereas binary files store data in the exact binary format held in memory.", "EASY"),
    ("Comp Sci", "File Handling", "What does the read(n) method do?", "It reads at most 'n' characters (or bytes) from the file and returns them as a string (or bytes object).", "EASY"),
    ("Comp Sci", "File Handling", "What is the default file opening mode in Python?", "'r' (read mode) for text files.", "EASY"),
    ("Comp Sci", "File Handling", "How does the 'x' mode behave?", "It opens a file for exclusive creation. If the file already exists, the operation fails and raises a FileExistsError.", "HARD"),
    ("Comp Sci", "File Handling", "What is the purpose of the flush() method?", "It forcefully writes the internal buffer's data to the disk file immediately, without waiting for the file to be closed.", "MODERATE"),
    ("Comp Sci", "File Handling", "What does the file.close() method do?", "It flushes any unwritten information and closes the file object, freeing up system resources.", "EASY"),
    ("Comp Sci", "File Handling", "If you open a file in 'a' mode, where is the file pointer placed?", "At the end of the file.", "MODERATE"),
    ("Comp Sci", "File Handling", "How do you find out the current position of the file pointer?", "By using the tell() method.", "EASY"),
    ("Comp Sci", "File Handling", "In seek(offset, whence), what does whence=2 signify?", "It sets the reference point to the end of the file (seek relative to the file's end).", "HARD"),
    ("Comp Sci", "File Handling", "Can you use seek() with whence=2 in text files in Python 3?", "Generally no, except for seek(0, 2) to jump to the end. Non-zero offsets relative to the end are only permitted in binary files.", "HARD"),
    ("Comp Sci", "File Handling", "What is a relative path?", "A file path that is relative to the current working directory, not starting from the root directory.", "MODERATE"),
    ("Comp Sci", "File Handling", "What module can be used to check if a file exists before opening it?", "The 'os' or 'os.path' module (e.g., os.path.exists(filename)).", "MODERATE"),
    ("Comp Sci", "File Handling", "What is returned by the readlines() method?", "A list containing each line of the file as a separate string element, including the newline characters.", "MODERATE"),
    ("Comp Sci", "File Handling", "What happens if you use write() with an integer argument?", "It raises a TypeError; write() only accepts strings for text files (or bytes for binary files).", "HARD"),
    ("Comp Sci", "File Handling", "What are standard input, output, and error streams?", "Built-in file objects (sys.stdin, sys.stdout, sys.stderr) used by the interpreter for standard I/O operations.", "HARD"),

    # Binary Files
    ("Comp Sci", "Binary Files", "Which module is required to read and write binary files in Python?", "The 'pickle' module.", "EASY"),
    ("Comp Sci", "Binary Files", "Differentiate between pickle.dump() and pickle.load().", "dump() is used for serialization (writing objects to a binary file), while load() is used for deserialization (reading).", "MODERATE"),
    ("Comp Sci", "Binary Files", "Which exception is commonly raised when pickle.load() reaches the end of a binary file?", "EOFError (End of File Error).", "HARD"),
    ("Comp Sci", "Binary Files", "What file mode is used to read a binary file?", "'rb' (read binary).", "EASY"),
    ("Comp Sci", "Binary Files", "What file mode is used to append data to an existing binary file?", "'ab' (append binary).", "EASY"),
    ("Comp Sci", "Binary Files", "Define pickling in Python.", "The process of converting a Python object hierarchy into a byte stream.", "MODERATE"),
    ("Comp Sci", "Binary Files", "Why are binary files faster to read and write than text files?", "Because data is stored in the same format as it is held in memory, requiring no translation or encoding.", "HARD"),
    ("Comp Sci", "Binary Files", "What is serialization in Python?", "The process of converting a complex Python object (like a list or dictionary) into a byte stream for storage or transmission.", "MODERATE"),
    ("Comp Sci", "Binary Files", "What is deserialization in Python?", "The process of converting a byte stream back into a Python object hierarchy.", "MODERATE"),
    ("Comp Sci", "Binary Files", "Which function is used to convert an object to a byte stream without writing to a file?", "pickle.dumps() (returns a bytes object instead of writing to a file).", "HARD"),
    ("Comp Sci", "Binary Files", "Which function is used to reconstruct a Python object from a byte string?", "pickle.loads()", "HARD"),
    ("Comp Sci", "Binary Files", "Why must binary files be opened in 'wb' or 'rb' modes?", "Because the 'pickle' module writes and reads bytes, not strings. Using 'w' or 'r' will cause TypeErrors.", "EASY"),
    ("Comp Sci", "Binary Files", "If you pickle multiple objects into a file, how do you read them back?", "You must call pickle.load() multiple times in the same order until an EOFError is raised.", "MODERATE"),
    ("Comp Sci", "Binary Files", "Is the pickle format human-readable?", "No, it is a binary format intended for Python to read and execute.", "EASY"),
    ("Comp Sci", "Binary Files", "Is it safe to unpickle data received from an untrusted source?", "No, unpickling malicious data can execute arbitrary code on your machine.", "HARD"),
    ("Comp Sci", "Binary Files", "Give two examples of Python objects that can be pickled.", "Lists, dictionaries, integers, strings, tuples, and user-defined class instances.", "EASY"),
    ("Comp Sci", "Binary Files", "How do you append a new record (dictionary) to an existing binary file?", "Open the file in 'ab' (append binary) mode and use pickle.dump() to write the new record.", "MODERATE"),
    ("Comp Sci", "Binary Files", "How can you search for a specific record in a binary file containing multiple dictionaries?", "Open in 'rb' mode, use a try-except EOFError block, load each dictionary using pickle.load(), and check if the dictionary matches the search criteria.", "HARD"),
    ("Comp Sci", "Binary Files", "How do you update a specific record in a binary file?", "Read all records into a list, modify the target record in the list, open the file in 'wb' mode, and dump the records back.", "HARD"),
    ("Comp Sci", "Binary Files", "What error is raised if you try to pickle.load() an empty file?", "EOFError.", "MODERATE"),
    ("Comp Sci", "Binary Files", "Which method is commonly used to bypass EOFError when reading all objects from a binary file?", "Wrapping the pickle.load() inside an infinite while loop within a try...except EOFError block.", "MODERATE"),
    ("Comp Sci", "Binary Files", "Can you easily view the contents of a binary file using Notepad?", "No, it will display as gibberish or unreadable characters.", "EASY"),

    # CSV Files
    ("Comp Sci", "CSV Files", "What is a CSV file?", "CSV stands for Comma Separated Values. It is a plain text file that stores tabular data using a specific delimiter.", "EASY"),
    ("Comp Sci", "CSV Files", "Why do we use the newline='' parameter when opening a file to write CSV data?", "To prevent blank lines (extra newlines) from being inserted between rows in Windows environments.", "HARD"),
    ("Comp Sci", "CSV Files", "What is the difference between writerow() and writerows() in the csv module?", "writerow() writes a single row (list) to the CSV, while writerows() writes multiple rows (a list of lists).", "MODERATE"),
    ("Comp Sci", "CSV Files", "What object is returned by the csv.reader() function?", "An iterable reader object that parses lines from the given CSV file into lists of strings.", "MODERATE"),
    ("Comp Sci", "CSV Files", "How can you change the default comma separator to a tab in a CSV file?", "By passing the argument delimiter='\\t' to the csv.writer() or csv.reader() function.", "HARD"),
    ("Comp Sci", "CSV Files", "Which Python module must be imported to work with CSV files?", "The 'csv' module.", "EASY"),
    ("Comp Sci", "CSV Files", "Does a CSV file store data types (like int or float)?", "No, everything in a CSV file is stored and read as text/strings.", "MODERATE"),
    ("Comp Sci", "CSV Files", "What is the full form of CSV?", "Comma Separated Values.", "EASY"),
    ("Comp Sci", "CSV Files", "What is a delimiter in a CSV file?", "A character (like a comma, tab, or pipe) used to separate individual fields/columns of data.", "EASY"),
    ("Comp Sci", "CSV Files", "Why are CSV files often preferred over Excel files for simple data transfer?", "They are plain text, lightweight, and can be read by almost any programming language or spreadsheet software.", "MODERATE"),
    ("Comp Sci", "CSV Files", "How do you write a list of values as a row to a CSV file?", "Using the writerow() method of the csv.writer object.", "EASY"),
    ("Comp Sci", "CSV Files", "How do you write a list of lists (multiple rows) to a CSV file at once?", "Using the writerows() method.", "MODERATE"),
    ("Comp Sci", "CSV Files", "What is the purpose of the next() function when reading a CSV file?", "It advances the reader iterator by one row, commonly used to skip the header row.", "HARD"),
    ("Comp Sci", "CSV Files", "Does csv.reader() automatically convert numerical strings into integers?", "No, all data is read as strings.", "MODERATE"),
    ("Comp Sci", "CSV Files", "How do you specify a different delimiter, like a pipe '|', when creating a writer object?", "csv.writer(file_object, delimiter='|')", "MODERATE"),
    ("Comp Sci", "CSV Files", "What does csv.DictReader do?", "It reads rows into dictionaries, using the first row as the keys (headers).", "HARD"),
    ("Comp Sci", "CSV Files", "What does csv.DictWriter do?", "It writes dictionaries to a CSV file, matching dictionary keys to the specified header fields.", "HARD"),
    ("Comp Sci", "CSV Files", "What data structure does csv.reader return upon iterating?", "It returns each row as a list of strings.", "MODERATE"),
    ("Comp Sci", "CSV Files", "Can a CSV file contain images or formatting like bold text?", "No, it only stores raw plain text data.", "EASY"),
    ("Comp Sci", "CSV Files", "If a CSV file has 5 columns, what is the length of the list returned for each row by csv.reader?", "5.", "EASY"),

    # Exception Handling
    ("Comp Sci", "Exception Handling", "What is the difference between a Syntax Error and an Exception?", "Syntax errors occur during parsing when code violates rules, while exceptions occur during execution (runtime errors).", "MODERATE"),
    ("Comp Sci", "Exception Handling", "What is the purpose of the 'finally' block?", "It contains code that is always executed, regardless of whether an exception was raised or handled.", "EASY"),
    ("Comp Sci", "Exception Handling", "Which keyword is used to force a specified exception to occur?", "The 'raise' keyword.", "MODERATE"),
    ("Comp Sci", "Exception Handling", "When does a ZeroDivisionError occur?", "When a division or modulo operation is attempted with zero as the denominator.", "EASY"),
    ("Comp Sci", "Exception Handling", "What is the purpose of the 'else' block in a try-except statement?", "The code in the 'else' block executes only if no exception was raised in the 'try' block.", "HARD"),
    ("Comp Sci", "Exception Handling", "When is a ValueError raised?", "When a built-in operation or function receives an argument that has the right type but an inappropriate value.", "MODERATE"),
    ("Comp Sci", "Exception Handling", "When is an IndexError raised?", "When trying to access an index in a sequence (like a list or tuple) that is out of range.", "EASY"),
    ("Comp Sci", "Exception Handling", "What is a runtime error?", "An error that occurs during the execution of a program, often due to illegal operations like dividing by zero or opening a non-existent file.", "EASY"),
    ("Comp Sci", "Exception Handling", "Name the block used to write code that might raise an exception.", "The 'try' block.", "EASY"),
    ("Comp Sci", "Exception Handling", "What is the use of the 'except' block?", "It catches and handles the exception raised by the try block, preventing the program from crashing.", "EASY"),
    ("Comp Sci", "Exception Handling", "Can a try block have multiple except blocks?", "Yes, it can have multiple except blocks to handle different types of exceptions separately.", "MODERATE"),
    ("Comp Sci", "Exception Handling", "What does 'except Exception as e:' do?", "It catches any standard exception and assigns the exception object to the variable 'e' for logging or inspection.", "MODERATE"),
    ("Comp Sci", "Exception Handling", "When does a NameError occur?", "When a local or global name is not found (e.g., trying to print an undeclared variable).", "EASY"),
    ("Comp Sci", "Exception Handling", "When does a TypeError occur?", "When an operation or function is applied to an object of inappropriate type (e.g., adding a string to an integer).", "MODERATE"),
    ("Comp Sci", "Exception Handling", "What happens if an exception is raised in the try block but there is no matching except block?", "The program terminates abruptly and displays a traceback (unhandled exception).", "HARD"),
    ("Comp Sci", "Exception Handling", "When is the 'else' block executed in exception handling?", "Only if no exception is raised within the 'try' block.", "MODERATE"),
    ("Comp Sci", "Exception Handling", "Why is it a bad practice to use a bare 'except:' clause?", "Because it catches all exceptions, including SystemExit and KeyboardInterrupt, making it difficult to debug unexpected errors.", "HARD"),
    ("Comp Sci", "Exception Handling", "When does an IOError (or OSError) typically occur?", "When an input/output operation fails, such as 'file not found' or 'disk full'.", "MODERATE"),
    ("Comp Sci", "Exception Handling", "How do you manually trigger a ValueError with the message 'Invalid input'?", "By using the statement: raise ValueError('Invalid input')", "HARD"),
    ("Comp Sci", "Exception Handling", "When does a KeyError occur?", "When a dictionary key is not found in the set of existing keys.", "EASY"),
    ("Comp Sci", "Exception Handling", "In a try-except-finally structure, what happens if a 'return' statement is executed inside the try block?", "The 'finally' block is still executed before the function actually returns the value.", "HARD"),
    ("Comp Sci", "Exception Handling", "What is an AssertionError?", "An exception raised when an 'assert' statement fails (evaluates to False), often used for debugging.", "HARD"),

    # Database Concepts
    ("Comp Sci", "Database Concepts", "Define 'Degree' and 'Cardinality' of a relation.", "Degree is the number of attributes (columns) in a table, and Cardinality is the number of tuples (rows).", "MODERATE"),
    ("Comp Sci", "Database Concepts", "What is a Primary Key?", "A column or a set of columns that uniquely identifies each row in a table. It cannot be NULL.", "EASY"),
    ("Comp Sci", "Database Concepts", "What is the difference between a Candidate Key and an Alternate Key?", "All attributes that can act as a primary key are Candidate Keys. Those not selected as the primary key become Alternate Keys.", "HARD"),
    ("Comp Sci", "Database Concepts", "Explain the concept of a Foreign Key.", "It is a non-key attribute in one table that derives its value from the primary key of another table.", "MODERATE"),
    ("Comp Sci", "Database Concepts", "What is an RDBMS?", "Relational Database Management System; a system that manages data stored in tables (relations) linked by common fields.", "EASY"),
    ("Comp Sci", "Database Concepts", "What is a tuple in the context of a database?", "A single row or record in a relational database table.", "EASY"),
    ("Comp Sci", "Database Concepts", "What does data redundancy mean?", "The unnecessary duplication of data within a database.", "MODERATE"),
    ("Comp Sci", "Database Concepts", "What is a domain in a relational database?", "The set of all possible valid values that an attribute (column) can contain.", "MODERATE"),
    ("Comp Sci", "Database Concepts", "What is the difference between data and information?", "Data consists of raw, unorganized facts, while information is processed, organized data that has meaning.", "EASY"),
    ("Comp Sci", "Database Concepts", "Define 'Attribute' in a relation.", "A characteristic or parameter of an entity, represented by a column in a table.", "EASY"),
    ("Comp Sci", "Database Concepts", "What is an entity?", "A real-world object, person, place, or concept about which data is stored in the database.", "EASY"),
    ("Comp Sci", "Database Concepts", "What is data inconsistency?", "It occurs when different and conflicting versions of the same data exist in different places within a database.", "MODERATE"),
    ("Comp Sci", "Database Concepts", "How does a database eliminate data redundancy?", "By normalizing data and storing it centrally, preventing the same piece of data from being stored in multiple tables.", "MODERATE"),
    ("Comp Sci", "Database Concepts", "Can a table have multiple candidate keys?", "Yes, a table can have multiple attributes or combinations of attributes capable of acting as a primary key.", "MODERATE"),
    ("Comp Sci", "Database Concepts", "Can a table have multiple primary keys?", "No, a table can strictly have only one primary key (though it can be a composite key made of multiple columns).", "HARD"),
    ("Comp Sci", "Database Concepts", "What is a Composite Primary Key?", "A primary key that consists of two or more attributes working together to uniquely identify a record.", "HARD"),
    ("Comp Sci", "Database Concepts", "Define Referential Integrity.", "A database concept that ensures relationships between tables remain consistent, usually enforced via Foreign Keys.", "HARD"),
    ("Comp Sci", "Database Concepts", "What happens to a foreign key if the primary key it references is deleted (assuming RESTRICT constraint)?", "The database will reject the deletion of the primary key record to maintain referential integrity.", "HARD"),
    ("Comp Sci", "Database Concepts", "What is a 'View' in a database?", "A virtual table whose contents are defined by a query on one or more underlying base tables.", "HARD"),
    ("Comp Sci", "Database Concepts", "What does a DBA (Database Administrator) do?", "A person responsible for the installation, configuration, upgrading, administration, and security of a database.", "MODERATE"),
    ("Comp Sci", "Database Concepts", "Give an example of a 1:M (One-to-Many) relationship.", "One Customer can place Many Orders, but each Order belongs to only One Customer.", "MODERATE"),
    ("Comp Sci", "Database Concepts", "Are all Alternate Keys also Candidate Keys?", "Yes, alternate keys are simply the candidate keys that were NOT chosen to be the primary key.", "MODERATE"),

    # SQL Queries
    ("Comp Sci", "SQL Queries", "What is the role of the DISTINCT keyword in SQL?", "It is used in a SELECT statement to return only unique (different) values, eliminating duplicates.", "EASY"),
    ("Comp Sci", "SQL Queries", "How do the '%' and '_' wildcards work in the LIKE clause?", "'%' represents zero, one, or multiple characters, while '_' represents exactly one single character.", "MODERATE"),
    ("Comp Sci", "SQL Queries", "Write the clause used to sort the result set of an SQL query.", "ORDER BY (followed by ASC or DESC).", "EASY"),
    ("Comp Sci", "SQL Queries", "How do you check for empty (NULL) values in a specific column?", "Using the 'IS NULL' operator (e.g., WHERE column_name IS NULL).", "MODERATE"),
    ("Comp Sci", "SQL Queries", "What is the purpose of the BETWEEN operator?", "It selects values within a given range, inclusive of the boundary values.", "EASY"),
    ("Comp Sci", "SQL Queries", "What is the IN operator used for?", "It allows you to specify multiple exact values in a WHERE clause, acting as shorthand for multiple OR conditions.", "MODERATE"),
    ("Comp Sci", "SQL Queries", "Can you use aliases for column names in SQL?", "Yes, using the 'AS' keyword (e.g., SELECT column_name AS alias_name).", "EASY"),
    ("Comp Sci", "SQL Queries", "How do you select all columns from a table named 'Employees'?", "SELECT * FROM Employees;", "EASY"),
    ("Comp Sci", "SQL Queries", "What is the wildcard character used to match any single character in a LIKE clause?", "The underscore character (_).", "EASY"),
    ("Comp Sci", "SQL Queries", "Write a query to find names starting with 'A' and ending with 'Z'.", "SELECT Name FROM table WHERE Name LIKE 'A%Z';", "MODERATE"),
    ("Comp Sci", "SQL Queries", "How is sorting in descending order achieved in SQL?", "By using the 'DESC' keyword after the column name in the ORDER BY clause.", "EASY"),
    ("Comp Sci", "SQL Queries", "Can ORDER BY take multiple columns? Give an example.", "Yes. Example: ORDER BY Department ASC, Salary DESC;", "HARD"),
    ("Comp Sci", "SQL Queries", "Write a query to display records where the 'City' is either Delhi, Mumbai, or Chennai without using OR.", "SELECT * FROM table WHERE City IN ('Delhi', 'Mumbai', 'Chennai');", "MODERATE"),
    ("Comp Sci", "SQL Queries", "How do you fetch records where 'Commission' is NULL?", "SELECT * FROM table WHERE Commission IS NULL;", "MODERATE"),
    ("Comp Sci", "SQL Queries", "Why is 'Commission = NULL' incorrect?", "In SQL, nothing is equal to NULL, not even NULL itself. You must use the IS NULL operator.", "HARD"),
    ("Comp Sci", "SQL Queries", "What is the default sort order for the ORDER BY clause?", "Ascending order (ASC).", "EASY"),
    ("Comp Sci", "SQL Queries", "Write a query to find prices strictly between 100 and 500 (excluding 100 and 500) without using BETWEEN.", "SELECT * FROM table WHERE Price > 100 AND Price < 500;", "HARD"),
    ("Comp Sci", "SQL Queries", "Does the BETWEEN operator include the boundary values?", "Yes, BETWEEN is inclusive of both boundary values.", "MODERATE"),
    ("Comp Sci", "SQL Queries", "How do you display calculated columns, like 10% of Salary as 'Bonus'?", "SELECT Salary * 0.10 AS Bonus FROM table;", "MODERATE"),
    ("Comp Sci", "SQL Queries", "What operator is used for pattern matching in SQL?", "The LIKE operator.", "EASY"),
    ("Comp Sci", "SQL Queries", "Write a query to select unique Departments from an Employee table.", "SELECT DISTINCT Department FROM Employee;", "MODERATE"),
    ("Comp Sci", "SQL Queries", "Write a query to find names that contain exactly 4 characters.", "SELECT Name FROM table WHERE Name LIKE '____';", "HARD"),

    # DDL Commands
    ("Comp Sci", "DDL Commands", "What is a DDL command? Give two examples.", "Data Definition Language commands deal with the structure of the database. Examples: CREATE TABLE, DROP TABLE, ALTER TABLE.", "MODERATE"),
    ("Comp Sci", "DDL Commands", "How is the ALTER command different from the UPDATE command?", "ALTER modifies the table structure (DDL), while UPDATE modifies the data inside the table (DML).", "HARD"),
    ("Comp Sci", "DDL Commands", "Which command is used to remove an entire table structure and its data from the database?", "DROP TABLE.", "EASY"),
    ("Comp Sci", "DDL Commands", "Write the syntax to add a new column 'Age' of integer type to a table 'Student'.", "ALTER TABLE Student ADD Age INT;", "MODERATE"),
    ("Comp Sci", "DDL Commands", "What constraint is used to ensure a column cannot have a NULL value?", "NOT NULL constraint.", "EASY"),
    ("Comp Sci", "DDL Commands", "Which command is used to delete a specific column from a table?", "ALTER TABLE table_name DROP column_name;", "MODERATE"),
    ("Comp Sci", "DDL Commands", "What is the DEFAULT constraint in table creation?", "It provides a default value for a column when none is specified during an INSERT operation.", "MODERATE"),
    ("Comp Sci", "DDL Commands", "Which command is used to add a Primary Key constraint to an existing table?", "ALTER TABLE table_name ADD PRIMARY KEY (column_name);", "HARD"),
    ("Comp Sci", "DDL Commands", "Which command changes the data type of an existing column?", "ALTER TABLE table_name MODIFY column_name new_datatype;", "HARD"),
    ("Comp Sci", "DDL Commands", "What does the UNIQUE constraint do?", "It ensures that all values in a column are distinct, but unlike a Primary Key, it allows NULL values.", "MODERATE"),
    ("Comp Sci", "DDL Commands", "What is the syntax to create a database?", "CREATE DATABASE database_name;", "EASY"),
    ("Comp Sci", "DDL Commands", "Which command brings a specific database into use?", "USE database_name;", "EASY"),
    ("Comp Sci", "DDL Commands", "What is the difference between DROP TABLE and DROP DATABASE?", "DROP TABLE deletes a single table and its data. DROP DATABASE deletes the entire database and all tables within it.", "MODERATE"),
    ("Comp Sci", "DDL Commands", "What is the FOREIGN KEY constraint used for in DDL?", "To link two tables together and enforce referential integrity.", "MODERATE"),
    ("Comp Sci", "DDL Commands", "Can a single DDL command alter multiple columns at once?", "Yes, multiple ADD or MODIFY clauses can be combined in a single ALTER TABLE statement separated by commas.", "HARD"),
    ("Comp Sci", "DDL Commands", "What constraint limits the range of values that can be inserted into a column?", "The CHECK constraint (e.g., CHECK (Age >= 18)).", "HARD"),
    ("Comp Sci", "DDL Commands", "If a table contains data, can you decrease the size of a VARCHAR column using ALTER?", "Only if the existing data in that column is smaller than or equal to the new reduced size.", "HARD"),
    ("Comp Sci", "DDL Commands", "Write the DDL command to rename a table from 'Emp' to 'Employee'.", "RENAME TABLE Emp TO Employee; (or ALTER TABLE Emp RENAME TO Employee; depending on SQL dialect).", "MODERATE"),
    ("Comp Sci", "DDL Commands", "What data type would you use in DDL to store fixed-length strings?", "CHAR(size).", "EASY"),
    ("Comp Sci", "DDL Commands", "What data type would you use in DDL to store variable-length strings?", "VARCHAR(size).", "EASY"),
    ("Comp Sci", "DDL Commands", "How do you specify a default value of 'Unknown' for a column 'City' during table creation?", "City VARCHAR(50) DEFAULT 'Unknown'", "MODERATE"),
    ("Comp Sci", "DDL Commands", "Are DDL commands auto-committed in MySQL?", "Yes, DDL commands are generally auto-committed and cannot be rolled back.", "HARD"),

    # DML Commands
    ("Comp Sci", "DML Commands", "What is a DML command? Give two examples.", "Data Manipulation Language commands deal with data manipulation. Examples: INSERT, UPDATE, DELETE.", "MODERATE"),
    ("Comp Sci", "DML Commands", "What is the difference between DELETE and DROP?", "DELETE removes rows from a table (DML). DROP removes the entire table structure from the database (DDL).", "HARD"),
    ("Comp Sci", "DML Commands", "Write the query to change the city of a student with RollNo 1 to 'Delhi'.", "UPDATE Student SET City = 'Delhi' WHERE RollNo = 1;", "MODERATE"),
    ("Comp Sci", "DML Commands", "What happens if you run an UPDATE command without a WHERE clause?", "It will update the specified column(s) for ALL rows in the table.", "HARD"),
    ("Comp Sci", "DML Commands", "Which command is used to add new rows of data into a table?", "INSERT INTO.", "EASY"),
    ("Comp Sci", "DML Commands", "What happens if you run a DELETE command without a WHERE clause?", "It will delete all rows from the table, but the table structure will remain intact.", "MODERATE"),
    ("Comp Sci", "DML Commands", "Can DML commands be rolled back?", "Yes, changes made by DML commands (like INSERT, UPDATE, DELETE) can typically be rolled back.", "HARD"),
    ("Comp Sci", "DML Commands", "Write the syntax to insert a record into all columns of a table.", "INSERT INTO table_name VALUES (value1, value2, ...);", "EASY"),
    ("Comp Sci", "DML Commands", "How do you insert data into specific columns only?", "INSERT INTO table_name (column1, column2) VALUES (value1, value2);", "MODERATE"),
    ("Comp Sci", "DML Commands", "What happens to the columns you omit during an INSERT operation?", "They are populated with their DEFAULT values, or NULL if no default is specified.", "MODERATE"),
    ("Comp Sci", "DML Commands", "Write a query to increase the salary of all employees by 5%.", "UPDATE Employee SET Salary = Salary * 1.05;", "HARD"),
    ("Comp Sci", "DML Commands", "How do you delete records of employees in the 'Sales' department?", "DELETE FROM Employee WHERE Department = 'Sales';", "MODERATE"),
    ("Comp Sci", "DML Commands", "What is the difference between DELETE and TRUNCATE?", "DELETE is a DML command that can use a WHERE clause and be rolled back. TRUNCATE is a DDL command that rapidly deletes all rows and cannot be rolled back.", "HARD"),
    ("Comp Sci", "DML Commands", "Can an UPDATE statement change multiple columns at once?", "Yes, by separating the column assignments with commas (e.g., SET col1=val1, col2=val2).", "MODERATE"),
    ("Comp Sci", "DML Commands", "Why must you be extremely careful with DML commands like UPDATE and DELETE?", "Because executing them without a WHERE clause will apply the changes to every single row in the table.", "EASY"),
    ("Comp Sci", "DML Commands", "Can we insert multiple rows with a single INSERT INTO statement?", "Yes, by providing multiple sets of values separated by commas.", "HARD"),
    ("Comp Sci", "DML Commands", "Write a query to delete all records from a table named 'Log' without dropping the table.", "DELETE FROM Log;", "EASY"),
    ("Comp Sci", "DML Commands", "If a column has a NOT NULL constraint and no default value, what happens if you omit it in an INSERT statement?", "The database will throw an error and the insertion will fail.", "HARD"),
    ("Comp Sci", "DML Commands", "What command is used to save DML changes permanently to the database?", "COMMIT;", "MODERATE"),
    ("Comp Sci", "DML Commands", "What command is used to undo uncommitted DML changes?", "ROLLBACK;", "MODERATE"),
    ("Comp Sci", "DML Commands", "Is the SELECT statement considered a DML command?", "Yes, it is often classified as a DML (or DQL - Data Query Language) command as it accesses/manipulates the display of data.", "EASY"),
    ("Comp Sci", "DML Commands", "Can DML commands modify the structure of a table (like adding a column)?", "No, modifying structure is strictly done using DDL commands.", "EASY"),

    # Aggregate Functions
    ("Comp Sci", "Aggregate Functions", "Name the five standard aggregate functions in SQL.", "SUM(), AVG(), COUNT(), MIN(), and MAX().", "EASY"),
    ("Comp Sci", "Aggregate Functions", "What is the difference between COUNT(*) and COUNT(column_name)?", "COUNT(*) counts all rows including NULLs, whereas COUNT(column_name) counts only the non-NULL values.", "HARD"),
    ("Comp Sci", "Aggregate Functions", "Which aggregate function is used to find the total of a numeric column?", "SUM()", "EASY"),
    ("Comp Sci", "Aggregate Functions", "Do aggregate functions consider NULL values?", "Except for COUNT(*), aggregate functions ignore NULL values in their calculations.", "MODERATE"),
    ("Comp Sci", "Aggregate Functions", "What will MAX() return for a string column?", "It will return the highest value based on alphabetical (lexicographical) order.", "MODERATE"),
    ("Comp Sci", "Aggregate Functions", "Can aggregate functions be used in the WHERE clause?", "No, they cannot be used in a WHERE clause; they must be used in the SELECT list or a HAVING clause.", "HARD"),
    ("Comp Sci", "Aggregate Functions", "Why are aggregate functions also called multiple-row functions?", "Because they operate on a set of rows and return a single summary value for that group.", "MODERATE"),
    ("Comp Sci", "Aggregate Functions", "Which aggregate function can be used with both numeric and string data types?", "MIN(), MAX(), and COUNT().", "HARD"),
    ("Comp Sci", "Aggregate Functions", "If a column 'Bonus' has values (100, NULL, 300), what is the result of SUM(Bonus)?", "400 (NULL values are ignored).", "MODERATE"),
    ("Comp Sci", "Aggregate Functions", "If a table has 5 rows, but the 'Bonus' column has values (100, NULL, 300, NULL, 200), what will COUNT(Bonus) return?", "3 (It counts only the non-NULL values).", "HARD"),
    ("Comp Sci", "Aggregate Functions", "What will COUNT(*) return for the table in the previous question?", "5 (It counts the total number of rows, regardless of NULLs).", "HARD"),
    ("Comp Sci", "Aggregate Functions", "Write a query to find the average salary of employees.", "SELECT AVG(Salary) FROM Employee;", "EASY"),
    ("Comp Sci", "Aggregate Functions", "What happens if you use AVG() on a string column?", "It will result in a syntax or type error, as mathematical average cannot be computed on strings.", "MODERATE"),
    ("Comp Sci", "Aggregate Functions", "Write a query to count the number of distinct departments.", "SELECT COUNT(DISTINCT Department) FROM Employee;", "HARD"),
    ("Comp Sci", "Aggregate Functions", "What does MIN(Name) return for a column of employee names?", "The name that appears first alphabetically.", "MODERATE"),
    ("Comp Sci", "Aggregate Functions", "Can aggregate functions be nested (e.g., MAX(AVG(Salary)))?", "Generally no, SQL does not allow direct nesting of aggregate functions without using subqueries or GROUP BY.", "HARD"),
    ("Comp Sci", "Aggregate Functions", "If there are zero rows in a table, what does SUM() return?", "NULL.", "HARD"),
    ("Comp Sci", "Aggregate Functions", "If there are zero rows in a table, what does COUNT() return?", "0.", "HARD"),
    ("Comp Sci", "Aggregate Functions", "Write a query to find the highest price of a product.", "SELECT MAX(Price) FROM Products;", "EASY"),
    ("Comp Sci", "Aggregate Functions", "Are aggregate functions executed before or after the WHERE clause?", "After. The WHERE clause filters the rows first, and then the aggregate function is applied to the remaining rows.", "MODERATE"),
    ("Comp Sci", "Aggregate Functions", "Can you select a standard column alongside an aggregate function without using GROUP BY (e.g., SELECT Name, MAX(Salary))?", "No, this will cause an error because a single aggregate value cannot be mapped to multiple individual names without grouping.", "HARD"),

    # GROUP BY
    ("Comp Sci", "GROUP BY", "What is the purpose of the GROUP BY clause?", "It is used to arrange identical data into groups, often used with aggregate functions.", "MODERATE"),
    ("Comp Sci", "GROUP BY", "How is the HAVING clause different from the WHERE clause?", "WHERE filters rows before grouping, while HAVING filters groups after the GROUP BY clause has been applied.", "HARD"),
    ("Comp Sci", "GROUP BY", "Can we use a GROUP BY clause without an aggregate function?", "Yes, but it typically behaves similarly to using the DISTINCT keyword.", "MODERATE"),
    ("Comp Sci", "GROUP BY", "What determines the columns placed in the GROUP BY clause?", "Any non-aggregate column present in the SELECT statement must be included in the GROUP BY clause.", "HARD"),
    ("Comp Sci", "GROUP BY", "Which keyword is used to filter aggregated data?", "HAVING.", "EASY"),
    ("Comp Sci", "GROUP BY", "In what order do WHERE, GROUP BY, and HAVING execute?", "First WHERE filters the rows, then GROUP BY groups them, and finally HAVING filters the groups.", "HARD"),
    ("Comp Sci", "GROUP BY", "What is the execution order of WHERE, GROUP BY, and HAVING?", "1. WHERE (filters rows), 2. GROUP BY (groups rows), 3. HAVING (filters groups).", "HARD"),
    ("Comp Sci", "GROUP BY", "Write a query to find the total salary paid in each department.", "SELECT Department, SUM(Salary) FROM Employee GROUP BY Department;", "MODERATE"),
    ("Comp Sci", "GROUP BY", "Why is HAVING used instead of WHERE for filtering aggregate values?", "Because the WHERE clause cannot evaluate aggregate functions; it filters rows before aggregation occurs.", "HARD"),
    ("Comp Sci", "GROUP BY", "Can you use GROUP BY on multiple columns?", "Yes, e.g., GROUP BY Department, JobTitle creates subgroups for each job title within each department.", "HARD"),
    ("Comp Sci", "GROUP BY", "Write a query to find departments having an average salary greater than 50000.", "SELECT Department, AVG(Salary) FROM Employee GROUP BY Department HAVING AVG(Salary) > 50000;", "MODERATE"),

    # JOINS
    ("Comp Sci", "JOINS", "What is a Cartesian Product (Cross Join)?", "It pairs every row of the first table with every row of the second table.", "MODERATE"),
    ("Comp Sci", "JOINS", "Define an Equi-Join.", "A join that combines tables based on a condition of equality ('=') between columns of the two tables.", "MODERATE"),
    ("Comp Sci", "JOINS", "What is a Natural Join?", "It is a type of Equi-Join where the duplicate column is omitted from the result set, appearing only once.", "HARD"),
    ("Comp Sci", "JOINS", "What determines the degree of a Cartesian product of two tables?", "The sum of the degrees (number of columns) of both tables.", "HARD"),
    ("Comp Sci", "JOINS", "What determines the cardinality of a Cartesian product of two tables?", "The product of the cardinalities (number of rows) of both tables.", "HARD"),
    ("Comp Sci", "JOINS", "Why are table aliases useful when performing joins?", "They simplify the query syntax and resolve ambiguity when both tables share a column with the same name.", "EASY"),
    ("Comp Sci", "JOINS", "If Table A has 4 rows and Table B has 5 rows, what is the cardinality of their Cartesian product?", "20 (4 x 5).", "EASY"),
    ("Comp Sci", "JOINS", "If Table A has 3 columns and Table B has 2 columns, what is the degree of their Cartesian product?", "5 (3 + 2).", "EASY"),
    ("Comp Sci", "JOINS", "Write the syntax for an Equi-Join between 'Emp' and 'Dept' on 'DeptID'.", "SELECT * FROM Emp, Dept WHERE Emp.DeptID = Dept.DeptID;", "MODERATE"),
    ("Comp Sci", "JOINS", "What is a primary requirement for performing a meaningful Equi-Join?", "Both tables must share a common column containing matching data values.", "MODERATE"),
    ("Comp Sci", "JOINS", "How does a Natural Join differ from an Equi-Join?", "A Natural Join automatically joins on all identically named columns and removes the duplicate joining column from the result set.", "HARD"),
    ("Comp Sci", "JOINS", "What is the problem with a Cartesian product (Cross Join) without a WHERE clause?", "It pairs every row in the first table with every row in the second table, resulting in mostly meaningless data combinations.", "HARD"),
    ("Comp Sci", "JOINS", "In a join query, what does 'Emp.Name' signify?", "It is a fully qualified column name, specifying that the 'Name' column comes explicitly from the 'Emp' table.", "EASY"),
    ("Comp Sci", "JOINS", "If two tables are joined using a condition with the '>' operator, what type of join is it?", "A Non-Equi Join.", "HARD"),
    ("Comp Sci", "JOINS", "What does the query 'SELECT * FROM A CROSS JOIN B' produce?", "A Cartesian product.", "MODERATE"),
    ("Comp Sci", "JOINS", "Why do we use table aliases (e.g., FROM Employee E, Department D)?", "To make writing complex queries with fully qualified column names shorter and easier to read.", "MODERATE"),

    # Networks
    ("Comp Sci", "Networks", "Expand the terms LAN, MAN, and WAN.", "Local Area Network (LAN), Metropolitan Area Network (MAN), and Wide Area Network (WAN).", "EASY"),
    ("Comp Sci", "Networks", "What is the difference between a Hub and a Switch?", "A Hub broadcasts data to all devices, whereas a Switch sends data only to the specific intended destination using MAC addresses.", "MODERATE"),
    ("Comp Sci", "Networks", "What is a network topology? Name any three.", "It is the physical or logical arrangement of devices in a network. Examples: Star, Bus, Ring, Tree, Mesh.", "EASY"),
    ("Comp Sci", "Networks", "In which topology is a central controller or hub required?", "Star Topology.", "EASY"),
    ("Comp Sci", "Networks", "What is the purpose of a Router?", "A router connects different networks together and routes data packets between them based on IP addresses.", "MODERATE"),
    ("Comp Sci", "Networks", "Differentiate between MAC address and IP address.", "A MAC address is a physical, hardcoded address of a NIC, while an IP address is a logical address.", "HARD"),
    ("Comp Sci", "Networks", "What is a Modem?", "Modulator-Demodulator. It converts digital signals into analog signals for telephone lines, and vice versa.", "MODERATE"),
    ("Comp Sci", "Networks", "What is VoIP?", "Voice over Internet Protocol allows making voice calls using a broadband Internet connection instead of a regular phone line.", "MODERATE"),
    ("Comp Sci", "Networks", "Expand HTTP and HTTPS. What is the difference?", "HTTPS encrypts the data transfer for security, whereas HTTP transmits in plain text.", "HARD"),
    ("Comp Sci", "Networks", "What is the role of a DNS server?", "Domain Name System (DNS) translates human-readable domain names (like google.com) into numerical IP addresses.", "MODERATE"),
    ("Comp Sci", "Networks", "What is the main advantage of a Mesh topology?", "High fault tolerance; if one link fails, data can take an alternate path.", "HARD"),
    ("Comp Sci", "Networks", "What is a Gateway?", "A network node that connects two networks using different protocols, often acting as an entry/exit point.", "MODERATE"),
    ("Comp Sci", "Networks", "What is the primary function of a Repeater?", "To regenerate and amplify a weak electrical, light, or radio signal to extend the geographical range of a network.", "MODERATE"),
    ("Comp Sci", "Networks", "Define Bandwidth.", "The maximum rate of data transfer across a given path, usually measured in bits per second (bps).", "EASY"),
    ("Comp Sci", "Networks", "How many bits are there in a MAC address?", "48 bits (usually represented as 12 hexadecimal digits).", "HARD"),
    ("Comp Sci", "Networks", "How many bits are there in an IPv4 address?", "32 bits (represented as four decimal octets).", "MODERATE"),
    ("Comp Sci", "Networks", "What is the difference between IPv4 and IPv6?", "IPv4 uses a 32-bit address space, while IPv6 uses a 128-bit address space to accommodate a vastly larger number of devices.", "HARD"),
    ("Comp Sci", "Networks", "What is a URL?", "Uniform Resource Locator; it is the global address of documents and other resources on the World Wide Web.", "EASY"),
    ("Comp Sci", "Networks", "What protocol is used for securely transferring files over the internet?", "SFTP (Secure File Transfer Protocol) or FTPS.", "HARD"),
    ("Comp Sci", "Networks", "Expand TCP/IP.", "Transmission Control Protocol / Internet Protocol.", "EASY"),
    ("Comp Sci", "Networks", "What is the role of TCP in the TCP/IP model?", "It breaks data into packets, ensures they are sent and received reliably in order, and handles error checking.", "HARD"),
    ("Comp Sci", "Networks", "What is a PAN?", "Personal Area Network; a network covering a very small area, usually within a room, like connecting a phone to Bluetooth headphones.", "EASY"),
    ("Comp Sci", "Networks", "Name a protocol used for sending emails.", "SMTP (Simple Mail Transfer Protocol).", "MODERATE"),
    ("Comp Sci", "Networks", "Name a protocol used for receiving emails.", "POP3 (Post Office Protocol version 3) or IMAP (Internet Message Access Protocol).", "MODERATE"),
    ("Comp Sci", "Networks", "What does a Firewall do?", "It is a network security system that monitors and controls incoming and outgoing network traffic based on predetermined security rules.", "MODERATE"),
    ("Comp Sci", "Networks", "In which topology is every node connected to exactly two other nodes, forming a single continuous pathway for signals?", "Ring Topology.", "EASY"),
    ("Comp Sci", "Networks", "What happens in a Bus topology if the main cable (backbone) breaks?", "The entire network goes down and communication stops completely.", "HARD"),
    ("Mathematics", "Relations and Functions", "Define a reflexive relation.", "A relation R in a set A is called reflexive if (a, a) belongs to R for every a in A.", "EASY"),
    ("Mathematics", "Relations and Functions", "Define a symmetric relation.", "A relation R in a set A is symmetric if (a, b) in R implies (b, a) is in R for all a, b in A.", "EASY"),
    ("Mathematics", "Relations and Functions", "Define a transitive relation.", "A relation R in a set A is transitive if (a, b) in R and (b, c) in R implies (a, c) is in R.", "EASY"),
    ("Mathematics", "Relations and Functions", "What is an equivalence relation?", "A relation that is reflexive, symmetric, and transitive.", "EASY"),
    ("Mathematics", "Relations and Functions", "Define a one-one (injective) function.", "A function f: X -> Y is one-one if f(x1) = f(x2) implies x1 = x2 for every x1, x2 in X.", "EASY"),
    ("Mathematics", "Relations and Functions", "Define an onto (surjective) function.", "A function f: X -> Y is onto if for every y in Y, there exists an x in X such that f(x) = y.", "EASY"),
    ("Mathematics", "Relations and Functions", "Define a bijective function.", "A function that is both one-one (injective) and onto (surjective).", "EASY"),
    ("Mathematics", "Relations and Functions", "Let R be the relation in the set N given by R = {(a, b) : a = b - 2, b > 6}. Is (6, 8) in R?", "Yes, because 6 = 8 - 2 and 8 > 6.", "MODERATE"),
    ("Mathematics", "Relations and Functions", "Let R be the relation in set {1, 2, 3} given by R = {(1, 2), (2, 1)}. Is R transitive?", "No, because (1,2) and (2,1) are in R, but (1,1) is not in R.", "MODERATE"),
    ("Mathematics", "Relations and Functions", "Is the function f: R -> R defined by f(x) = x^2 one-one?", "No, because f(1) = f(-1) = 1, meaning different inputs map to the same output.", "EASY"),
    ("Mathematics", "Relations and Functions", "Is the function f: R -> R defined by f(x) = x^2 onto?", "No, because negative real numbers in the codomain have no pre-image in the domain.", "EASY"),
    ("Mathematics", "Relations and Functions", "Find the number of all one-one functions from set A={1, 2, 3} to itself.", "3! = 6 functions.", "MODERATE"),
    ("Mathematics", "Relations and Functions", "Let A = {1, 2, 3}. Then what is the number of equivalence relations containing (1, 2)?", "2 relations.", "HARD"),
    ("Mathematics", "Relations and Functions", "Show that the relation 'is congruent to' on the set of all triangles is an equivalence relation.", "Every triangle is congruent to itself (reflexive); if T1 is congruent to T2, T2 is congruent to T1 (symmetric); if T1 is congruent to T2 and T2 to T3, T1 is congruent to T3 (transitive).", "MODERATE"),
    ("Mathematics", "Relations and Functions", "Let f: R -> R be defined as f(x) = 3x. Is f one-one and onto?", "Yes, it is a bijective function.", "EASY"),
    ("Mathematics", "Relations and Functions", "Let R be a relation on the set A of real numbers defined as R = {(a, b): a <= b^2}. Is R reflexive, symmetric, or transitive?", "It is neither reflexive (e.g., 1/2 is not <= (1/2)^2), nor symmetric (e.g., 1 <= 3^2 but 3 is not <= 1^2), nor transitive (e.g., 2 <= (-1.5)^2, -1.5 <= 1.2^2, but 2 is not <= 1.2^2).", "HARD"),
    ("Mathematics", "Relations and Functions", "What is the maximum number of equivalence relations on the set A = {1, 2, 3}?", "5 equivalence relations.", "HARD"),
    ("Mathematics", "Relations and Functions", "Let R be the equivalence relation in the set A = {0, 1, 2, 3, 4, 5} given by R = {(a, b) : 2 divides (a - b)}. Find the equivalence class [0].", "{0, 2, 4}.", "MODERATE"),
    ("Mathematics", "Relations and Functions", "Let f: N -> N be defined by f(n) = n+1 if n is odd, and n-1 if n is even. Is f bijective?", "Yes, it is both one-one and onto.", "HARD"),
    ("Mathematics", "Relations and Functions", "A relation R on A={1,2,3} is R={(1,1),(2,2),(3,3),(1,2),(2,3)}. What is the minimum number of ordered pairs to add to make it an equivalence relation?", "Four pairs: (2,1), (3,2), (1,3), and (3,1).", "HARD"),
    # Inverse Trigonometric Functions
    ("Mathematics", "Inverse Trigonometric Functions", "What is the principal value branch of sin^-1(x)?", "[-pi/2, pi/2]", "EASY"),
    ("Mathematics", "Inverse Trigonometric Functions", "What is the principal value branch of cos^-1(x)?", "[0, pi]", "EASY"),
    ("Mathematics", "Inverse Trigonometric Functions", "What is the principal value branch of tan^-1(x)?", "(-pi/2, pi/2)", "EASY"),
    ("Mathematics", "Inverse Trigonometric Functions", "Find the principal value of sin^-1(1/sqrt(2)).", "pi/4", "EASY"),
    ("Mathematics", "Inverse Trigonometric Functions", "Find the principal value of cos^-1(-1/2).", "2pi/3", "MODERATE"),
    ("Mathematics", "Inverse Trigonometric Functions", "Evaluate the value of tan^-1(1) + cos^-1(-1/2) + sin^-1(-1/2).", "3pi/4", "HARD"),
    ("Mathematics", "Inverse Trigonometric Functions", "Find the value of cos(sec^-1 x + csc^-1 x), for |x| >= 1.", "0 (since the inner sum is pi/2)", "MODERATE"),
    ("Mathematics", "Inverse Trigonometric Functions", "Find the domain of sin^-1(2x).", "[-1/2, 1/2]", "MODERATE"),
    ("Mathematics", "Inverse Trigonometric Functions", "Write the value of sin(pi/3 - sin^-1(-1/2)).", "1", "HARD"),
    ("Mathematics", "Inverse Trigonometric Functions", "Find the principal value of tan^-1(-sqrt(3)).", "-pi/3", "EASY"),
    ("Mathematics", "Inverse Trigonometric Functions", "Find the value of cos^-1(cos(7pi/6)).", "5pi/6", "MODERATE"),
    ("Mathematics", "Inverse Trigonometric Functions", "Evaluate tan^-1(tan(3pi/4)).", "-pi/4", "MODERATE"),
    ("Mathematics", "Inverse Trigonometric Functions", "What is the domain of cos^-1(x)?", "[-1, 1]", "EASY"),
    ("Mathematics", "Inverse Trigonometric Functions", "Simplify tan^-1[ (sqrt(1+x^2) - 1) / x ].", "(1/2)tan^-1(x)", "HARD"),
    ("Mathematics", "Inverse Trigonometric Functions", "What substitution is useful to prove 3 sin^-1 x = sin^-1(3x - 4x^3)?", "x = sin(theta)", "MODERATE"),
    ("Mathematics", "Inverse Trigonometric Functions", "Find the value of sin^-1(sin(2pi/3)).", "pi/3", "MODERATE"),
    ("Mathematics", "Inverse Trigonometric Functions", "Express tan^-1(cosx / (1 - sinx)) in its simplest form.", "pi/4 + x/2", "HARD"),
    ("Mathematics", "Inverse Trigonometric Functions", "Evaluate sin(2 cos^-1(-3/5)).", "-24/25", "HARD"),
    ("Mathematics", "Inverse Trigonometric Functions", "Is the function f(x) = sin^-1(x) + cos^-1(x) a constant?", "Yes, it equals pi/2 for all x in [-1, 1].", "EASY"),
    ("Mathematics", "Inverse Trigonometric Functions", "Write the principal value of cot^-1(-1/sqrt(3)).", "2pi/3", "MODERATE"),
    # Matrices
    ("Mathematics", "Matrices", "Define a scalar matrix.", "A diagonal matrix in which all the diagonal elements are equal.", "EASY"),
    ("Mathematics", "Matrices", "Define a diagonal matrix.", "A square matrix in which all non-diagonal elements are zero.", "EASY"),
    ("Mathematics", "Matrices", "What is a symmetric matrix?", "A square matrix A is symmetric if A^T = A.", "EASY"),
    ("Mathematics", "Matrices", "What is a skew-symmetric matrix?", "A square matrix A is skew-symmetric if A^T = -A.", "EASY"),
    ("Mathematics", "Matrices", "If a matrix has 18 elements, what are the possible orders it can have?", "1x18, 18x1, 2x9, 9x2, 3x6, 6x3", "MODERATE"),
    ("Mathematics", "Matrices", "Construct a 2x2 matrix A=[aij] whose elements are given by aij = (i+j)^2 / 2. Find a12.", "9/2", "MODERATE"),
    ("Mathematics", "Matrices", "If A and B are symmetric matrices of the same order, then what type of matrix is AB - BA?", "A skew-symmetric matrix.", "HARD"),
    ("Mathematics", "Matrices", "If A = [cos x, -sin x; sin x, cos x], find x such that A + A^T = I.", "x = pi/3", "HARD"),
    ("Mathematics", "Matrices", "Write the condition for two matrices A and B to be conformable for multiplication AB.", "The number of columns in A must equal the number of rows in B.", "EASY"),
    ("Mathematics", "Matrices", "Every square matrix can be uniquely expressed as the sum of which two types of matrices?", "A symmetric and a skew-symmetric matrix.", "MODERATE"),
    ("Mathematics", "Matrices", "If A is a square matrix such that A^2 = A, then (I+A)^3 - 7A is equal to?", "I (Identity matrix)", "HARD"),
    ("Mathematics", "Matrices", "For what value of x, is the matrix [0, 1, -2; -1, 0, 3; x, -3, 0] a skew-symmetric matrix?", "x = 2", "MODERATE"),
    ("Mathematics", "Matrices", "Find the value of a and b from: [a-b, 2a+c; 2a-b, 3c+d] = [-1, 5; 0, 13].", "a = 1, b = 2", "MODERATE"),
    ("Mathematics", "Matrices", "If A is a 3x3 matrix and |A| = 5, what is |3A|?", "27 * 5 = 135", "HARD"),
    ("Mathematics", "Matrices", "If matrix A is both symmetric and skew-symmetric, what can you say about A?", "A is a zero matrix.", "MODERATE"),
    ("Mathematics", "Matrices", "If A = [1, 2; 3, 4], find A^T.", "[1, 3; 2, 4]", "EASY"),
    ("Mathematics", "Matrices", "What can be said about the diagonal elements of a skew-symmetric matrix?", "They are all zero.", "EASY"),
    ("Mathematics", "Matrices", "If A and B are square matrices of the same order, does AB always equal BA?", "No, matrix multiplication is not commutative in general.", "EASY"),
    ("Mathematics", "Matrices", "Let A = [0, 1; 0, 0]. Evaluate A^2.", "A zero matrix (O).", "MODERATE"),
    ("Mathematics", "Matrices", "Write a 3x3 identity matrix.", "[1, 0, 0; 0, 1, 0; 0, 0, 1]", "EASY"),
    # Determinants
    ("Mathematics", "Determinants", "Evaluate the determinant of [2, 4; -1, 2].", "2(2) - 4(-1) = 8", "EASY"),
    ("Mathematics", "Determinants", "If |x, 2; 18, x| = |6, 2; 18, 6|, find the possible values of x.", "x = 6 or -6", "MODERATE"),
    ("Mathematics", "Determinants", "Define a singular matrix.", "A square matrix whose determinant is zero.", "EASY"),
    ("Mathematics", "Determinants", "If A is a non-singular matrix of order 3 and |A| = 4, find |adj A|.", "4^(3-1) = 16", "HARD"),
    ("Mathematics", "Determinants", "Write the property of determinants if two rows are identical.", "The determinant is zero.", "EASY"),
    ("Mathematics", "Determinants", "How does the determinant change if rows and columns are interchanged?", "It remains unchanged.", "EASY"),
    ("Mathematics", "Determinants", "If A is an invertible matrix of order 2, then det(A^-1) is equal to?", "1 / det(A)", "MODERATE"),
    ("Mathematics", "Determinants", "Find the area of the triangle with vertices (2, 7), (1, 1) and (10, 8) using determinants.", "47/2 square units", "MODERATE"),
    ("Mathematics", "Determinants", "Write the formula for the inverse of a matrix A using its determinant and adjoint.", "A^-1 = 1/|A| * adj(A)", "EASY"),
    ("Mathematics", "Determinants", "If the area of a triangle formed by three points is zero, what can be said about the points?", "They are collinear.", "EASY"),
    ("Mathematics", "Determinants", "Find the minor of element 6 in the determinant |1, 2, 3; 4, 5, 6; 7, 8, 9|.", "-6", "MODERATE"),
    ("Mathematics", "Determinants", "Find the cofactor of element a21 (value 4) in |1, 2, 3; 4, 5, 6; 7, 8, 9|.", "6", "MODERATE"),
    ("Mathematics", "Determinants", "If A is a matrix of order 3x3 and |A| = -5, find the value of |2A|.", "-40", "MODERATE"),
    ("Mathematics", "Determinants", "Solve using matrix method (Cramer's rule): 2x + 5y = 1, 3x + 2y = 7.", "x = 3, y = -1", "HARD"),
    ("Mathematics", "Determinants", "What is the value of the determinant of an identity matrix of order n?", "1", "EASY"),
    ("Mathematics", "Determinants", "If A(adj A) = 10 I, where I is the identity matrix of order 3, find |A|.", "10", "HARD"),
    ("Mathematics", "Determinants", "Determine the value of k if the matrix [k, 2; 3, 4] is singular.", "k = 3/2", "MODERATE"),
    ("Mathematics", "Determinants", "Let A be a non-singular square matrix of order 3x3. Then |adj(adj A)| is equal to?", "|A|^4", "HARD"),
    ("Mathematics", "Determinants", "Evaluate |sin x, cos x; -cos x, sin x|.", "1", "EASY"),
    ("Mathematics", "Determinants", "If A is a 3x3 invertible matrix, find the value of k if det(adj(2A)) = k(det A)^2.", "det(adj(2A)) = (det(2A))^(n-1) = (det(2A))^2. Since A is 3x3, det(2A) = 2^3 det(A) = 8 det(A). So, (8 det(A))^2 = 64 (det A)^2. Hence, k = 64.", "HARD"),
    # Continuity and Differentiability
    ("Mathematics", "Continuity and Differentiability", "A function f(x) is continuous at x=c if?", "The limit of f(x) as x approaches c is equal to f(c).", "EASY"),
    ("Mathematics", "Continuity and Differentiability", "Differentiate sin(x^2) with respect to x.", "2x cos(x^2)", "EASY"),
    ("Mathematics", "Continuity and Differentiability", "Differentiate e^sin(x) with respect to x.", "e^sin(x) * cos(x)", "MODERATE"),
    ("Mathematics", "Continuity and Differentiability", "Find dy/dx if y = x^x.", "x^x (1 + log x)", "HARD"),
